        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
      }
      succeeded++;
      continue;
    }

    try {
      removeExisting(action.target, verbose);
      mkdirSync(path.dirname(action.target), { recursive: true });

      if (action.method === "symlink") {
