  } else {
    if (verbose) {
      console.log(`    \x1b[33m!\x1b[0m replacing existing directory: ${targetPath}`);
    }
    rmSync(targetPath, { recursive: true });
  }
}

function isSymlink(p: string): boolean {
  try {
    return lstatSync(p).isSymbolicLink();
  } catch {
    return false;
  }
}

